16	function initParticles(canvas: HTMLCanvasElement, getState: () => VoiceState) {
17	  const ctx = canvas.getContext('2d');
18	  if (!ctx) return () => undefined;
19	
20	  const resize = () => {
21	    canvas.width = window.innerWidth;
22	    canvas.height = window.innerHeight;
23	  };
24	  resize();
25	  window.addEventListener('resize', resize);
26	
27	  const particles = Array.from({ length: 520 }, () => ({
28	    x: (Math.random() - 0.5) * 48,
29	    y: (Math.random() - 0.5) * 48,
30	    z: (Math.random() - 0.5) * 48,
31	    vx: (Math.random() - 0.5) * 0.02,
32	    vy: (Math.random() - 0.5) * 0.02,
33	    vz: (Math.random() - 0.5) * 0.02,
34	    radius: Math.random() * 1.5 + 0.35,
35	  }));
36	
37	  const palette: Record<VoiceState, [number, number, number]> = {
38	    dormant: [141, 92, 246],
39	    listening: [255, 92, 0],
40	    processing: [0, 255, 136],
41	    speaking: [244, 114, 182],
42	  };
43	
44	  let rotation = 0;
45	  let raf = 0;
46	
47	  const draw = () => {
48	    const state = getState();
49	    const [r, g, b] = palette[state];
50	    const speed = state === 'processing' ? 1.5 : state === 'speaking' ? 1.2 : state === 'listening' ? 1 : 0.72;
51	
52	    ctx.clearRect(0, 0, canvas.width, canvas.height);
53	    rotation += 0.0015 * speed;
54	
55	    const cx = canvas.width / 2;
56	    const cy = canvas.height / 2;
57	    const projected = particles.map((particle) => {
58	      particle.x += particle.vx * speed;
59	      particle.y += particle.vy * speed;
60	      particle.z += particle.vz * speed;
61	
62	      if (particle.x > 24 || particle.x < -24) particle.vx *= -1;
63	      if (particle.y > 24 || particle.y < -24) particle.vy *= -1;
64	      if (particle.z > 24 || particle.z < -24) particle.vz *= -1;
65	
66	      const rx = particle.x * Math.cos(rotation) - particle.z * Math.sin(rotation);
67	      const rz = particle.x * Math.sin(rotation) + particle.z * Math.cos(rotation);
68	      const depth = 180 / (rz + 80);
69	
70	      return {
71	        x: cx + rx * depth,
72	        y: cy + particle.y * depth,
73	        alpha: Math.max(0.04, Math.min(0.48, depth * 0.11)),
74	        radius: particle.radius * depth,
75	      };
76	    });
77	
78	    for (let i = 0; i < projected.length; i += 1) {
79	      const a = projected[i];
80	      for (let j = i + 1; j < projected.length; j += 7) {
81	        const bPoint = projected[j];
82	        const dx = a.x - bPoint.x;
83	        const dy = a.y - bPoint.y;
84	        const dist = Math.sqrt(dx * dx + dy * dy);
85	        if (dist < 72) {
86	          ctx.beginPath();
87	          ctx.moveTo(a.x, a.y);
88	          ctx.lineTo(bPoint.x, bPoint.y);
89	          ctx.strokeStyle = `rgba(${r}, ${g}, ${b}, ${0.06 * (1 - dist / 72)})`;
90	          ctx.lineWidth = 0.5;
91	          ctx.stroke();
92	        }
93	      }
94	    }
95	
96	    for (const point of projected) {
97	      ctx.beginPath();
98	      ctx.arc(point.x, point.y, point.radius, 0, Math.PI * 2);
99	      ctx.fillStyle = `rgba(${r}, ${g}, ${b}, ${point.alpha})`;
100	      ctx.fill();
101	    }
102	
103	    raf = requestAnimationFrame(draw);
104	  };
105	
106	  draw();
107	  return () => {
108	    cancelAnimationFrame(raf);
109	    window.removeEventListener('resize', resize);
110	  };
111	}
