113	function useTypewriter() {
114	  const [text, setText] = useState('');
115	  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
116	
117	  const type = useCallback((full: string, pace = 20) => {
118	    if (timerRef.current) clearTimeout(timerRef.current);
119	    setText('');
120	
121	    let index = 0;
122	    const tick = () => {
123	      if (index < full.length) {
124	        setText(full.slice(0, index + 1));
125	        index += 1;
126	        timerRef.current = setTimeout(tick, pace);
127	      }
128	    };
129	
130	    tick();
131	  }, []);
132	
133	  return { text, setText, type };
134	}
