136	function playPCM(base64: string) {
137	  const binary = atob(base64);
138	  const bytes = new Uint8Array(binary.length);
139	  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
140	
141	  const header = new ArrayBuffer(44);
142	  const view = new DataView(header);
143	  const sampleRate = 24000;
144	  view.setUint32(0, 0x52494646, false);
145	  view.setUint32(4, 36 + bytes.length, true);
146	  view.setUint32(8, 0x57415645, false);
147	  view.setUint32(12, 0x666d7420, false);
148	  view.setUint32(16, 16, true);
149	  view.setUint16(20, 1, true);
150	  view.setUint16(22, 1, true);
151	  view.setUint32(24, sampleRate, true);
152	  view.setUint32(28, sampleRate * 2, true);
153	  view.setUint16(32, 2, true);
154	  view.setUint16(34, 16, true);
155	  view.setUint32(36, 0x64617461, false);
156	  view.setUint32(40, bytes.length, true);
157	
158	  return new Audio(URL.createObjectURL(new Blob([header, bytes], { type: 'audio/wav' })));
159	}
