539	          <button type="button" className={s.actionButton} onClick={wisdomPreservation} disabled={!lastExchange.user}>Preserve</button>
540	          {manifest && <button type="button" className={s.actionButtonGhost} onClick={() => setManifest(null)}>Clear</button>}
541	        </div>
