  line-height: 1.12;
  text-align: center;
  font-style: italic;
  color: rgba(255, 255, 255, 0.9);
  text-shadow: 0 0 18px rgba(180, 0, 255, 0.12);
}

.word {
  display: inline-block;
  opacity: 0;
  filter: blur(8px);
  transform: translateY(8px);
  transition: opacity 0.5s cubic-bezier(0.1, 0.9, 0.2, 1), transform 0.5s cubic-bezier(0.1, 0.9, 0.2, 1), filter 0.5s ease;
}

.wordVisible {
  opacity: 1;
  filter: blur(0);
  transform: translateY(0);
}

.wordDim {
  opacity: 0.1;
  filter: blur(2px);
}

/* Runtime panel */
.runtimePanel {
  width: min(880px, calc(100vw - 2rem));
  background: rgba(2, 2, 8, 0.82);
  border: 1px solid rgba(0, 229, 255, 0.07);
  border-radius: 14px;
  padding: 1rem 1.2rem;
  backdrop-filter: blur(22px);
  pointer-events: auto;
}

.runtimeHeader {
  margin-bottom: 0.8rem;
  color: rgba(0, 229, 255, 0.42);
  font-size: 0.56rem;
  letter-spacing: 0.42em;
  text-transform: uppercase;
  text-shadow: 0 0 8px rgba(0, 229, 255, 0.12);
}

.runtimeGrid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 0.7rem 1rem;
}

.runtimeItem,
.runtimeItemWide {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.runtimeItemWide {
  grid-column: 1 / -1;
}

.runtimeLabel {
  color: rgba(255, 255, 255, 0.26);
  font-size: 0.52rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

.runtimeValue {
  color: rgba(255, 255, 255, 0.82);
  font-size: 0.78rem;
}

.runtimeMono {
  color: rgba(0, 229, 255, 0.55);
  font-size: 0.68rem;
  word-break: break-all;
  font-family: 'Space Grotesk', monospace;
}

/* Manifestation */
