/* ────────────────────────────────────────────
   Neural Particle Field — magenta/cyan filaments + haze
   ──────────────────────────────────────────── */
function initParticles(canvas: HTMLCanvasElement, getState: () => VoiceState) {
  const ctx = canvas.getContext('2d');
  if (!ctx) return () => undefined;

  const resize = () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  };
  resize();
  window.addEventListener('resize', resize);

  const HAZE_COUNT = 180;
  const FILAMENT_COUNT = 340;

  const hazeParticles = Array.from({ length: HAZE_COUNT }, () => {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.random() * 14;
    return {
      x: Math.cos(angle) * dist,
      y: Math.sin(angle) * dist,
      z: (Math.random() - 0.5) * 10,
      vx: (Math.random() - 0.5) * 0.008,
      vy: (Math.random() - 0.5) * 0.008,
      vz: (Math.random() - 0.5) * 0.005,
      radius: Math.random() * 0.7 + 0.2,
      isCyan: Math.random() > 0.5,
    };
  });

  const filamentParticles = Array.from({ length: FILAMENT_COUNT }, () => {
    const angle = Math.random() * Math.PI * 2;
    const dist = Math.random() * 48 + 6;
    return {
      x: Math.cos(angle) * dist,
      y: Math.sin(angle) * dist,
      z: (Math.random() - 0.5) * 42,
      vx: (Math.random() - 0.5) * 0.016,
      vy: (Math.random() - 0.5) * 0.016,
      vz: (Math.random() - 0.5) * 0.014,
      radius: Math.random() * 1.1 + 0.3,
      isCyan: Math.random() > 0.5,
    };
  });

  type RGB = [number, number, number];
  const palettes: Record<string, Record<VoiceState, RGB>> = {
    magenta: {
      dormant: [160, 0, 220],
      listening: [220, 0, 140],
      processing: [100, 0, 255],
      speaking: [160, 0, 220],
    },
    cyan: {
      dormant: [0, 165, 200],
      listening: [0, 200, 230],
      processing: [0, 229, 255],
      speaking: [0, 150, 190],
    },
  };

  let rotation = 0;
  let raf = 0;

  const draw = () => {
    const state = getState();
    const speed = state === 'processing' ? 1.5 : state === 'speaking' ? 1.1 : state === 'listening' ? 0.95 : 0.55;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    rotation += 0.001 * speed;

    const cx = canvas.width / 2;
    const cy = canvas.height / 2;

    const project = (p: { x: number; y: number; z: number; radius: number; isCyan: boolean }) => {
      const rx = p.x * Math.cos(rotation) - p.z * Math.sin(rotation);
      const rz = p.x * Math.sin(rotation) + p.z * Math.cos(rotation);
      const depth = 190 / (rz + 85);
      const [r, g, b] = palettes[p.isCyan ? 'cyan' : 'magenta'][state];
      return { x: cx + rx * depth, y: cy + p.y * depth, alpha: Math.max(0.03, Math.min(0.45, depth * 0.1)), radius: p.radius * depth, r, g, b };
    };

    // Update haze — soft pull toward center
    for (const p of hazeParticles) {
      p.x += p.vx * speed;
      p.y += p.vy * speed;
      p.z += p.vz * speed;
      const dist = Math.sqrt(p.x * p.x + p.y * p.y);
      if (dist > 16) { p.vx -= p.x * 0.0008; p.vy -= p.y * 0.0008; }
      if (p.z > 6 || p.z < -6) p.vz *= -1;
    }

    // Update filaments — bounded drift
    for (const p of filamentParticles) {
      p.x += p.vx * speed;
      p.y += p.vy * speed;
      p.z += p.vz * speed;
      if (Math.abs(p.x) > 52) p.vx *= -1;
      if (Math.abs(p.y) > 52) p.vy *= -1;
      if (Math.abs(p.z) > 26) p.vz *= -1;
    }

    const projF = filamentParticles.map(project);
    const projH = hazeParticles.map(project);

    // Draw neural strand connections
    for (let i = 0; i < projF.length; i += 1) {
      const a = projF[i];
      for (let j = i + 1; j < projF.length; j += 5) {
        const b = projF[j];
        const dx = a.x - b.x;
        const dy = a.y - b.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 88) {
          const alpha = 0.04 * (1 - dist / 88);
          const mr = (a.r + b.r) >> 1;
          const mg = (a.g + b.g) >> 1;
          const mb = (a.b + b.b) >> 1;
          ctx.beginPath();
          ctx.moveTo(a.x, a.y);
          ctx.lineTo(b.x, b.y);
          ctx.strokeStyle = `rgba(${mr},${mg},${mb},${alpha})`;
          ctx.lineWidth = 0.4;
          ctx.stroke();
        }
      }
    }

    // Draw filament particles
    for (const p of projF) {
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${p.r},${p.g},${p.b},${p.alpha})`;
      ctx.fill();
    }

    // Draw haze — larger, softer
    for (const p of projH) {
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.radius * 2.8, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(${p.r},${p.g},${p.b},${p.alpha * 0.25})`;
      ctx.fill();
    }

    raf = requestAnimationFrame(draw);
  };

  draw();
  return () => {
    cancelAnimationFrame(raf);
    window.removeEventListener('resize', resize);
  };
}

/* ────────────────────────────────────────────
   Typewriter — pace adapts to text length
   ──────────────────────────────────────────── */
function useTypewriter() {
  const [text, setText] = useState('');
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const type = useCallback((full: string, pace?: number) => {
    if (timerRef.current) clearTimeout(timerRef.current);
    setText('');

    const effectivePace = pace ?? Math.max(12, Math.min(32, 900 / Math.max(full.length, 1)));
    let index = 0;
    const tick = () => {
      if (index < full.length) {
        setText(full.slice(0, index + 1));
        index += 1;
        timerRef.current = setTimeout(tick, effectivePace);
      }
    };

    tick();
  }, []);

  return { text, setText, type };
}

/* ────────────────────────────────────────────
   Audio playback — handles mp3 (ElevenLabs) and wav ()
   ──────────────────────────────────────────── */
function playAudio(base64: string, mimeType: string) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);

  // If it's already a complete audio file (mp3, wav with headers), use directly
  if (mimeType === 'audio/mpeg' || mimeType === 'audio/wav') {
    return new Audio(URL.createObjectURL(new Blob([bytes], { type: mimeType })));
  }

  // Legacy fallback: raw PCM → wrap in WAV header
  const header = new ArrayBuffer(44);
  const view = new DataView(header);
  const sampleRate = 24000;
  view.setUint32(0, 0x52494646, false);
  view.setUint32(4, 36 + bytes.length, true);
  view.setUint32(8, 0x57415645, false);
  view.setUint32(12, 0x666d7420, false);
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  view.setUint32(36, 0x64617461, false);
  view.setUint32(40, bytes.length, true);

  return new Audio(URL.createObjectURL(new Blob([header, bytes], { type: 'audio/wav' })));
}

