199	/* ────────────────────────────────────────────
200	   Audio playback — handles mp3 (ElevenLabs) and wav ()
201	   ──────────────────────────────────────────── */
202	function playAudio(base64: string, mimeType: string) {
203	  const binary = atob(base64);
204	  const bytes = new Uint8Array(binary.length);
205	  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
206	
207	  // If it's already a complete audio file (mp3, wav with headers), use directly
208	  if (mimeType === 'audio/mpeg' || mimeType === 'audio/wav') {
209	    return new Audio(URL.createObjectURL(new Blob([bytes], { type: mimeType })));
210	  }
211	
212	  // Legacy fallback: raw PCM → wrap in WAV header
213	  const header = new ArrayBuffer(44);
214	  const view = new DataView(header);
215	  const sampleRate = 24000;
216	  view.setUint32(0, 0x52494646, false);
217	  view.setUint32(4, 36 + bytes.length, true);
218	  view.setUint32(8, 0x57415645, false);
219	  view.setUint32(12, 0x666d7420, false);
220	  view.setUint32(16, 16, true);
221	  view.setUint16(20, 1, true);
222	  view.setUint16(22, 1, true);
223	  view.setUint32(24, sampleRate, true);
224	  view.setUint32(28, sampleRate * 2, true);
225	  view.setUint16(32, 2, true);
226	  view.setUint16(34, 16, true);
227	  view.setUint32(36, 0x64617461, false);
228	  view.setUint32(40, bytes.length, true);
229	
230	  return new Audio(URL.createObjectURL(new Blob([header, bytes], { type: 'audio/wav' })));
231	}
