import { NextRequest, NextResponse } from 'next/server';
import { neon } from '@neondatabase/serverless';

// Public read-only endpoint — no auth required.
// Returns safe-to-share entries from the public_knowledge table.

export async function GET(req: NextRequest) {
  const dbUrl = process.env.DATABASE_URL;
  if (!dbUrl) return NextResponse.json({ error: 'DB unavailable' }, { status: 503 });

  const { searchParams } = new URL(req.url);
  const category = searchParams.get('category');       // filter by category
  const tag      = searchParams.get('tag');            // filter by tag
  const q        = searchParams.get('q');              // simple text search
  const limit    = Math.min(parseInt(searchParams.get('limit') ?? '20', 10), 100);
  const offset   = parseInt(searchParams.get('offset') ?? '0', 10);

  try {
    const db = neon(dbUrl);

    // Build query dynamically
    const conditions: string[] = [];
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const params: any[] = [];
    let p = 1;

    if (category) { conditions.push(`category = $${p++}`); params.push(category); }
    if (tag)      { conditions.push(`$${p++} = ANY(tags)`); params.push(tag); }
    if (q)        { conditions.push(`content ILIKE $${p++}`); params.push(`%${q}%`); }

    const where = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';

    const rows = await db(
      `SELECT id, category, title, content, source_ns, importance, tags, published_at
       FROM public_knowledge
       ${where}
       ORDER BY importance DESC, published_at DESC
       LIMIT $${p++} OFFSET $${p++}`,
      [...params, limit, offset]
    );

    const countResult = await db(
      `SELECT count(*)::int AS total FROM public_knowledge ${where}`,
      params
    );

    return NextResponse.json(
      {
        total: countResult[0]?.total ?? 0,
        limit,
        offset,
        results: rows,
      },
      {
        headers: {
          'Cache-Control': 'public, s-maxage=60, stale-while-revalidate=300',
          'Access-Control-Allow-Origin': '*',
        },
      }
    );
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 500 });
  }
}

// CORS preflight
export async function OPTIONS() {
  return new NextResponse(null, {
    headers: {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, OPTIONS',
    },
  });
}

